const body = $json.body ?? $json;

const allowed = ["Nunca", "A veces", "Frecuentemente", "Casi siempre"];

const q1 = body.q1;
const q2 = body.q2;
const q3 = body.q3;
const q4 = body.q4;
const q5 = body.q5;

// 1) Validar que existan las 5 respuestas
const missing = [q1, q2, q3, q4, q5].some(v => v === undefined || v === null || v === "");

if (missing) {
  return [
    {
      json: {
        ok: false,
        blocked: true,
        error: "Faltan una o más respuestas. Se requieren q1, q2, q3, q4 y q5."
      }
    }
  ];
}

// 2) Validar longitud máxima básica
const maxLength = 30;
const tooLong = [q1, q2, q3, q4, q5].some(v => String(v).length > maxLength);

if (tooLong) {
  return [
    {
      json: {
        ok: false,
        blocked: true,
        error: "Una o más respuestas exceden la longitud permitida."
      }
    }
  ];
}

// 3) Validar whitelist estricta
const invalid = [q1, q2, q3, q4, q5].some(v => !allowed.includes(v));

if (invalid) {
  return [
    {
      json: {
        ok: false,
        blocked: true,
        error: "Una o más respuestas no son válidas. Usa solo: Nunca, A veces, Frecuentemente, Casi siempre."
      }
    }
  ];
}

// 4) Detección básica de prompt injection
const suspiciousPatterns = [
  "ignora instrucciones anteriores",
  "ignore previous instructions",
  "system prompt",
  "developer message",
  "actua como",
  "actúa como",
  "revela el prompt",
  "reveal the prompt",
  "jailbreak",
  "override",
  "bypass"
];

const answersText = [q1, q2, q3, q4, q5].join(" ").toLowerCase();
const suspiciousMatch = suspiciousPatterns.find(pattern => answersText.includes(pattern));

if (suspiciousMatch) {
  return [
    {
      json: {
        ok: false,
        blocked: true,
        error: "Entrada bloqueada por patrón sospechoso.",
        reason: suspiciousMatch
      }
    }
  ];
}

// 5) Construir bloque de usuario
const userBlock = `Pregunta 1: ${q1}
Pregunta 2: ${q2}
Pregunta 3: ${q3}
Pregunta 4: ${q4}
Pregunta 5: ${q5}`;

// 6) Prompt del sistema resumido para n8n
const systemPrompt = `Eres Sin Nudo AI, una guía conversacional diseñada para ayudar a mujeres que enfrentan bloqueos asociados al síndrome del impostor, especialmente en contextos de desempleo, presión económica, dudas sobre su valor profesional y pérdida de autonomía.

Tu objetivo es analizar las respuestas de la usuaria, identificar el nudo principal, detectar si existe un nudo secundario, explicar el bloqueo con lenguaje claro, empático y no clínico, y entregar una recomendación accionable y realista.

Los nudos posibles son:
1. Nudo de la desvalorización del logro
2. Nudo de la duda constante
3. Nudo de la evitación de oportunidades
4. Nudo de la presión económica
5. Nudo de la aceptación por necesidad

Cada pregunta corresponde a un nudo específico:
- Pregunta 1 → Nudo de la desvalorización del logro
- Pregunta 2 → Nudo de la duda constante
- Pregunta 3 → Nudo de la evitación de oportunidades
- Pregunta 4 → Nudo de la presión económica
- Pregunta 5 → Nudo de la aceptación por necesidad

Escala:
- Nunca = 0
- A veces = 1
- Frecuentemente = 2
- Casi siempre = 3

Si hay empate, prioriza en este orden:
1. Nudo de la aceptación por necesidad
2. Nudo de la presión económica
3. Nudo de la evitación de oportunidades
4. Nudo de la duda constante
5. Nudo de la desvalorización del logro

Responde en español con esta estructura exacta:

Nudo principal: [nombre del nudo]

Nudo secundario: [nombre del nudo o “No identificado”]

Interpretación:
[explica en 3 a 5 líneas qué refleja este resultado y cómo puede estar afectando sus decisiones]

Recomendación accionable:
- [acción 1]
- [acción 2]
- [acción 3]

Mensaje final:
[un cierre breve, cálido y motivador, de máximo 2 líneas]`;

return [
  {
    json: {
      ok: true,
      blocked: false,
      q1,
      q2,
      q3,
      q4,
      q5,
      userBlock,
      requestBody: {
        model: "Qwen/Qwen2.5-7B-Instruct",
        messages: [
          {
            role: "system",
            content: systemPrompt
          },
          {
            role: "user",
            content: userBlock
          }
        ],
        temperature: 0.2
      }
    }
  }
];
